function rand(min, max) { return Math.floor(Math.random() * (max - min + 1)) + min; }
function shuffleCalcOptions(correct, distractors){ let options = [correct, ...distractors]; for(let i = options.length - 1; i > 0; i--){ let j = Math.floor(Math.random() * (i + 1)); [options[i], options[j]] = [options[j], options[i]]; } return { options, a: options.indexOf(correct) }; }
function getMoneyDemandTargetCalc(){ let intercept = rand(180, 320); let slope = rand(20, 60); let r = rand(2, 6); let P = rand(5, 20); let real = intercept - slope * r; if(real <= 0){ real = 100; intercept = real + slope * r; } let M = real * P; let pack = shuffleCalcOptions(`$${M}`, [`$${real}`, `$${M + slope * P}`, `$${Math.max(P * (real - slope), 0)}`]); return {id:10000,q:`Money demand is L(r) = ${intercept} - ${slope}r and P = ${P}. If the Fed wants r = ${r}, what nominal money supply is needed?`,options:pack.options,a:pack.a,tag:"monetary_policy",type:"calculation",objective:"LO13.3",primarySkill:"monetary_policy_lm_shift",feedback:"Use the target interest rate to find real money demand, then multiply by the price level to get nominal money supply.",hint:"Find M/P first, then multiply by P."}; }
function getMoneySupplyChangeCalc(){ let intercept = rand(240, 420); let slope = rand(20, 50); let P = rand(5, 20); let r1 = rand(2, 6); let r2 = Math.max(1, r1 - 1); let M1 = (intercept - slope * r1) * P; let M2 = (intercept - slope * r2) * P; let change = M2 - M1; let pack = shuffleCalcOptions(`increase the money supply by $${change}`, [`decrease the money supply by $${change}`, `increase the money supply by $${Math.abs(change - slope)}`, `leave the money supply unchanged`]); return {id:10001,q:`Money demand is L(r) = ${intercept} - ${slope}r and P = ${P}. To move the interest rate from ${r1}% to ${r2}%, the Fed must do what?`,options:pack.options,a:pack.a,tag:"monetary_policy",type:"calculation",objective:"LO13.3",primarySkill:"monetary_policy_lm_shift",feedback:"A lower target interest rate requires more real balances. Compute M/P at both rates, then multiply by P and compare.",hint:"Lower r means higher money demand."}; }
function getKeynesianCrossCalc(){ let mpcChoices = [0.5, 0.6, 0.75, 0.8]; let mpc = mpcChoices[rand(0, mpcChoices.length - 1)]; let deltaG = rand(10, 40); let mult = 1 / (1 - mpc); let deltaY = Math.round(deltaG * mult * 10) / 10; let pack = shuffleCalcOptions(`planned expenditure rises by $${deltaG} billion; equilibrium income rises by $${deltaY} billion`, [`planned expenditure rises by $${deltaY} billion; equilibrium income rises by $${deltaG} billion`, `planned expenditure rises by $${deltaG} billion; equilibrium income rises by $${deltaG} billion`, `planned expenditure falls by $${deltaG} billion; equilibrium income falls by $${deltaY} billion`]); return {id:10002,q:`In the Keynesian-cross model, MPC = ${mpc}. A $${deltaG} billion increase in government purchases changes planned expenditure and equilibrium income by how much?`,options:pack.options,a:pack.a,tag:"fiscal_policy",type:"calculation",objective:"LO13.2",primarySkill:"fiscal_policy_is_shift",feedback:"Government purchases enter planned expenditure dollar-for-dollar, then the multiplier raises equilibrium income by 1/(1 - MPC) times the spending change.",hint:"Spending change first, multiplier second."}; }
function getPlannedExpenditureEquilibriumCalc(){ let A = rand(300, 700); let mpcChoices = [0.5, 0.6, 0.75, 0.8]; let mpc = mpcChoices[rand(0, mpcChoices.length - 1)]; let T = rand(50, 250); let I = rand(100, 400); let G = rand(150, 500); let numerator = A - mpc * T + I + G; let Y = Math.round((numerator / (1 - mpc)) * 10) / 10; let pack = shuffleCalcOptions(`$${Y}`, [`$${Math.round(numerator * 10) / 10}`, `$${Math.round((A + I + G) * 10) / 10}`, `$${Math.round((Y * (1 - mpc)) * 10) / 10}`]); return {id:10003,q:`Planned expenditure is PE = ${A} + ${mpc}(Y - T) + I + G, where T = ${T}, I = ${I}, and G = ${G}. At what income does actual expenditure equal planned expenditure?`,options:pack.options,a:pack.a,tag:"is_curve",type:"calculation",objective:"LO12.1",primarySkill:"is_curve_goods_market",feedback:"Set Y = PE, collect the Y terms on the left, and solve. The tax term reduces autonomous spending by MPC times T.",hint:"Set Y equal to PE."}; }
function getISLMSystemCalc(){ let r = rand(2, 6); let Y = rand(800, 1600); let isSlope = rand(20, 80); let lmSlope = rand(50, 120); let isIntercept = Y + isSlope * r; let lmIntercept = Y - lmSlope * r; let pack = shuffleCalcOptions(`Y = ${Y} and r = ${r}`, [`Y = ${Y + 100} and r = ${r}`, `Y = ${Y} and r = ${r + 1}`, `Y = ${Math.max(Y - 100, 0)} and r = ${Math.max(r - 1, 0)}`]); return {id:10004,q:`Suppose the IS curve is Y = ${isIntercept} - ${isSlope}r and the LM curve is Y = ${lmIntercept} + ${lmSlope}r. What are equilibrium income and the interest rate?`,options:pack.options,a:pack.a,tag:"is_lm_equilibrium",type:"calculation",objective:"LO12.3",primarySkill:"is_lm_equilibrium",feedback:"Set the IS equation equal to the LM equation, solve for r, then plug r into either equation to get Y.",hint:"Set IS equal to LM."}; }
function getADRealBalancesCalc(){ let M = rand(1500, 4000); let P1 = rand(8, 12); let P2 = Math.max(4, P1 - rand(1, 3)); let real1 = Math.round((M / P1) * 10) / 10; let real2 = Math.round((M / P2) * 10) / 10; let pack = shuffleCalcOptions(`real balances rise from ${real1} to ${real2}, shifting LM right and raising income`, [`real balances fall from ${real2} to ${real1}, shifting LM left and lowering income`, `real balances stay at ${real1}, so AD is vertical`, `real balances rise, shifting IS left and lowering income`]); return {id:10005,q:`Nominal money is M = ${M}. If the price level falls from ${P1} to ${P2}, what happens to real balances and why does this help derive AD?`,options:pack.options,a:pack.a,tag:"aggregate_demand",type:"calculation",objective:"LO13.4",primarySkill:"aggregate_demand_from_islm",feedback:"A lower price level raises M/P. Higher real balances shift LM right, lowering the interest rate and raising income, which gives the downward slope of AD.",hint:"Compute M/P before and after."}; }
window.calculationGenerators = [getMoneyDemandTargetCalc,getMoneySupplyChangeCalc,getKeynesianCrossCalc,getPlannedExpenditureEquilibriumCalc,getISLMSystemCalc,getADRealBalancesCalc];

console.log("Command Nexus external question bank loaded", { easy: window.questionBanks?.easy?.length, medium: window.questionBanks?.medium?.length, hard: window.questionBanks?.hard?.length, elite: window.questionBanks?.elite?.length, legendary: window.questionBanks?.legendary?.length });
